VALUES
  ('heelevel3-29a002de-moex-00081', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於甲、乙訂立買賣契約之敘述，何者錯誤？ 雙方約定依市價買賣甲所有之動產時，契約即為成立 雙方對於應為給付之清償地，未經表示意思者，推定其契約為成立 雙方對於應為給付之貨幣種類與方法，未經表示意思者，推定其契約為成立 雙方對於標的物交付後發生瑕疵時之修補費用之負擔，意思表示不一致者，契約即不成立', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00082', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '關於買賣之危險負擔，下列敘述，何者正確？ 倘若出賣人已將買賣標的物現實交付買受人，嗣後該標的物因不可歸責於雙方事由而滅失，買 受人不須給付價金 倘若出賣人已將買賣標的物現實交付買受人，但尚未移轉所有權前，被政府徵收，則買受人於 取得徵收補償金後，仍須給付價金 倘若出賣人以指示交付方式將買賣標的物交付買受人，嗣該標的物於第三人掌控支配中因地震 而滅失，則買受人仍須給付價金 倘若買受人請求出賣人將買賣標的物送交清償地以外之處所，於運送中發生標的物滅失，買受 人不須給付價金', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00083', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於合夥之敘述，何者錯誤？ 合夥負有債務者，債權人得優先就各合夥人之固有財產求償 合夥債務為合夥人之公同共有債務 合夥人對於合夥債務之清償，負補充之連帶責任 各合夥人之出資及其他合夥財產，為合夥人全體之公同共有', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00084', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲將其中古汽車出售並即交付於乙，惟甲與乙迄未至監理所辦理過戶登記手續，該車即被丙所竊。 關於物上請求權之行使，下列敘述，何者正確？ 因甲、乙尚未辦理過戶登記，甲仍為汽車之所有人，故僅得由原登記人甲向丙行使所有物返還 請求權 縱甲、乙尚未辦理過戶登記，乙仍取得所有權，故應由乙向丙行使所有物返還請求權 因甲、乙尚未辦理過戶登記，故甲及乙準共有所有物返還請求權，應由甲、乙共同行使之 因甲、乙尚未辦理過戶登記，故乙不得主張民法第767條之所有物返還請求權，僅得向丙主張 第962條之占有物返還請求權', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00085', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲、乙與丙三人登記為A地分別共有人，應有部分各三分之一。甲未經乙與丙同意，出賣A地於 丁，仍占有使用A地，並移轉自己應有部分於戊。下列敘述，何者錯誤？ 乙僅得請求甲，將A地返還於全體共有人 甲就未經乙與丙同意而占有使用A地一事，對乙與丙負侵權行為責任 甲與丁間之A地買賣，效力未定 甲與戊間就應有部分之處分，有效 33120', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00086', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲向乙買受房屋一棟，已交清價款，乙亦將房屋交付甲占有，惟未辦理所有權移轉登記，逾20年 後乙死亡，該屋由乙之子丙繼承並辦妥繼承登記。下列敘述，何者正確？ 甲以所有之意思，20年間和平、公然、繼續占有乙之不動產而時效取得所有權，故丙不得向甲 主張物上請求權，請求返還該房屋 甲之所有權移轉登記請求權雖罹於時效消滅，但甲之占有非屬無權占有，故丙不得向甲主張物 上請求權，請求返還該房屋 甲與乙間之買賣契約僅具有債之相對效力，不得對抗繼承人丙，故丙得向甲主張物上請求權， 請求返還該房屋 若丙為信賴不動產登記之善意繼承人，得向甲主張物上請求權請求返還該房屋；反之，若丙為 惡意繼承人，則不得主張之', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00087', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列何者非屬抵押人所得行使之權利？ 次序權之讓與    抵押物之占有 抵押物所有權之讓與  於抵押物上設定其他用益物權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00088', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲夫、乙妻攜全家老小出遊，因對振興五倍券使用上有所誤會，積欠旅遊業者丙新臺幣(下同)15 萬元未清償。甲夫月收10萬元，乙妻月收5萬元。下列敘述，何者正確？ 依甲、乙之經濟能力，丙僅得向乙請求5萬元之給付 依甲、乙之經濟能力，丙僅得向甲請求10萬元之給付 丙得就15萬元之給付，主張甲、乙連帶負責 夫妻各自對其債務負清償之責，丙僅得向簽約之甲請求15萬元之給付', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00089', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於收養關係之敘述，何者錯誤？ 被收養者自收養關係成立之日，與其養父母成立擬制之親子關係 養子女於收養關係存續中，與其本生父母之天然血親仍然存在 養子女於收養關係存續中，與其本生父母之權利義務關係，處於停止狀態 收養關係存續中，所謂直系血親卑親屬與父母關係，包含養子女與本生父母關係在內', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00090', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列何者不具有溯及效力？ 認領  法院認可收養  裁判減輕扶養義務  終止收養之撤銷', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
